using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = ManualConfig.Create(DefaultConfig.Instance)
    .AddJob(Job.MediumRun.WithId(".NET 9").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core90))
    .AddJob(Job.MediumRun.WithId(".NET 10").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core100));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _small = null!;
    private TextAnalyzer _medium = null!;
    private TextAnalyzer _large = null!;

    [GlobalSetup]
    public void Setup()
    {
        var rng = new Random(42);
        _small = new TextAnalyzer(GenerateText(rng, wordCount: 50));
        _medium = new TextAnalyzer(GenerateText(rng, wordCount: 500));
        _large = new TextAnalyzer(GenerateText(rng, wordCount: 5000));
    }

    private static string GenerateText(Random rng, int wordCount)
    {
        const string chars = "abcdefghijklmnopqrstuvwxyz";
        var words = new string[wordCount];
        for (int i = 0; i < wordCount; i++)
        {
            int len = rng.Next(1, 15);
            var buf = new char[len];
            for (int j = 0; j < len; j++)
                buf[j] = chars[rng.Next(chars.Length)];
            words[i] = new string(buf);
        }
        return string.Join(' ', words);
    }

    // --- AverageWordLength ---
    [Benchmark] public double AverageWordLength_Small() => _small.AverageWordLength();
    [Benchmark] public double AverageWordLength_Medium() => _medium.AverageWordLength();
    [Benchmark] public double AverageWordLength_Large() => _large.AverageWordLength();

    // --- WordLengthHistogram ---
    [Benchmark] public object WordLengthHistogram_Small() => _small.WordLengthHistogram();
    [Benchmark] public object WordLengthHistogram_Medium() => _medium.WordLengthHistogram();
    [Benchmark] public object WordLengthHistogram_Large() => _large.WordLengthHistogram();

    // --- UniqueWordCount ---
    [Benchmark] public int UniqueWordCount_Small() => _small.UniqueWordCount();
    [Benchmark] public int UniqueWordCount_Medium() => _medium.UniqueWordCount();
    [Benchmark] public int UniqueWordCount_Large() => _large.UniqueWordCount();
}

